module serial2parallel(
    input clk,
    input rst_n,
    input din_serial,
    input din_valid,
    output reg [7:0] dout_parallel,
    output reg dout_valid
);

    reg [2:0] counter;
    reg [7:0] shift_reg;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            counter <= 3'b000;
            shift_reg <= 8'b0000_0000;
            dout_parallel <= 8'b0000_0000;
            dout_valid <= 1'b0;
        end
        else if (din_valid) begin
            shift_reg <= {shift_reg[6:0], din_serial};
            counter <= counter + 1'b1;
            if (counter == 3'b111) begin
                dout_parallel <= shift_reg;
                dout_valid <= 1'b1;
            end
            else begin
                dout_valid <= 1'b0;
            end
        end
        else begin
            dout_valid <= 1'b0;
        end
    end

endmodule

module div_16bit(
    input clk,
    input rst,
    input sign,
    input [15:0] dividend,
    input [15:0] divisor,
    input opn_valid,
    input res_ready,
    output res_valid,
    output reg [15:0] result
);

    reg [15:0] dividend_ext;
    reg [7:0] divisor_ext;
    reg sign_dividend, sign_divisor;
    reg [15:0] quotient;
    reg [7:0] remainder;
    reg [3:0] i;

    always @(*) begin
        // Determine the sign of the dividend and divisor
        sign_dividend = sign & dividend[7];
        sign_divisor = sign & divisor[7];

        // Extend the dividend and divisor to 16 bits
        dividend_ext = {sign_dividend ? 8'b11111111 : 8'b00000000, dividend};
        divisor_ext = {sign_divisor ? 8'b11111111 : 8'b00000000, divisor};

        // Initialize the quotient and remainder
        quotient = 0;
        remainder = 0;

        // Perform the division
        for (i = 0; i < 8; i = i + 1) begin
            remainder = {remainder[6:0], dividend_ext[15-i]};
            if (remainder >= divisor_ext) begin
                remainder = remainder - divisor_ext;
                quotient = {quotient[14:0], 1'b1};
            end else begin
                quotient = {quotient[14:0], 1'b0};
            end
        end

        // Apply the sign to the result
        if (sign_dividend ^ sign_divisor) begin
            result = {1'b1, quotient[14:0]} + {8'b00000000, remainder};
        end else begin
            result = {1'b0, quotient[14:0]} + {8'b00000000, remainder};
        end
    end

endmodule

module width_8to16(
    input clk,
    input rst_n,
    input valid_in,
    input [7:0] data_in,
    output reg valid_out,
    output reg [15:0] data_out
);

reg [7:0] data_lock;
reg flag;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        valid_out <= 1'b0;
        data_out <= 16'b0;
        data_lock <= 8'b0;
        flag <= 1'b0;
    end
    else begin
        if (valid_in) begin
            if (flag) begin
                valid_out <= 1'b1;
                data_out <= {data_lock, data_in};
                flag <= 1'b0;
            end
            else begin
                valid_out <= 1'b0;
                data_lock <= data_in;
                flag <= 1'b1;
            end
        end
        else begin
            valid_out <= 1'b0;
            data_out <= 16'b0;
        end
    end
end

endmodule

module pe(
    input clk,
    input rst,
    input [31:0] a,
    input [31:0] b,
    output [31:0] c
);
  reg [31:0] res;
  always @(posedge clk or posedge rst) begin
    if (rst) res <= 0;
    else res <= res + a * b;
  end
  assign c = res;
endmodule

module traffic_light(
    input rst_n,
    input clk,
    input pass_request,
    output reg red,
    output reg yellow,
    output reg green
);

localparam GREEN_TIME = 60;
localparam YELLOW_TIME = 5;
localparam RED_TIME = 10;

reg [5:0] timer;
reg [1:0] state;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        timer <= 0;
        state <= 0;
        red <= 0;
        yellow <= 0;
        green <= 1;
    end else begin
        case (state)
            2'b00: begin // Green state
                if (timer == GREEN_TIME - 1) begin
                    state <= 2'b01; // Transition to Yellow state
                    timer <= 0;
                end else begin
                    timer <= timer + 1;
                end
                red <= 0;
                yellow <= 0;
                green <= 1;
            end
            2'b01: begin // Yellow state
                if (timer == YELLOW_TIME - 1) begin
                    state <= 2'b10; // Transition to Red state
                    timer <= 0;
                end else begin
                    timer <= timer + 1;
                end
                red <= 0;
                yellow <= 1;
                green <= 0;
            end
            2'b10: begin // Red state
                if (timer == RED_TIME - 1) begin
                    state <= 2'b00; // Transition to Green state
                    timer <= 0;
                end else begin
                    timer <= timer + 1;
                end
                red <= 1;
                yellow <= 0;
                green <= 0;
            end
            default: begin
                state <= 2'b00; // Default to Green state
            end
        endcase

        if (pass_request && timer > 10) begin
            state <= 2'b01; // Override to Yellow state if button is pressed
            timer <= 0;
        end
    end
end

endmodule

module multi_16bit(
    input clk,
    input rst_n,
    input start,
    input [15:0] ain,
    input [15:0] bin,
    output [31:0] yout,
    output done
);
    reg [31:0] yout_r;
    reg [15:0] areg;
    reg [15:0] breg;
    reg [16:0] i;
    reg done_r;
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            i <= 17'b0;
        end else if (start && i < 17) begin
            i <= i + 1;
        end else begin
            i <= 17'b0;
        end
    end
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            done_r <= 1'b0;
        end else if (i == 16) begin
            done_r <= 1'b1;
        end else if (i == 17) begin
            done_r <= 1'b0;
        end
    end
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            yout_r <= 32'b0;
            areg <= 16'b0;
            breg <= 16'b0;
            i <= 17'b0;
            done_r <= 1'b0;
        end else if (start) begin
            if (i == 17'b0) begin
                areg <= ain;
                breg <= bin;
            end else if (i < 17) begin
                if (areg[i-1]) begin
                    yout_r <= yout_r + (breg << (i-1) | 32'b0);
                end
            end
        end
    end
    assign yout = yout_r;
    assign done = done_r;
endmodule

module multi_pipe_8bit(
    input clk,
    input rst_n,
    input mul_en_in,
    input [7:0] mul_a,
    input [7:0] mul_b,
    output mul_en_out,
    output [15:0] mul_out
);

reg [7:0] mul_a_reg, mul_b_reg;
reg mul_en_in_reg;
reg [15:0] mul_out_reg;
reg mul_en_out_reg;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        mul_a_reg <= 8'b0;
        mul_b_reg <= 8'b0;
        mul_en_in_reg <= 1'b0;
        mul_out_reg <= 16'b0;
        mul_en_out_reg <= 1'b0;
    end else begin
        mul_a_reg <= mul_a;
        mul_b_reg <= mul_b;
        mul_en_in_reg <= mul_en_in;
        mul_out_reg <= mul_a_reg * mul_b_reg;
        mul_en_out_reg <= mul_en_in_reg;
    end
end

assign mul_out = mul_out_reg;
assign mul_en_out = mul_en_out_reg;

endmodule

module parallel2serial(
    input clk,
    input rst_n,
    input [3:0] d,
    output valid_out,
    output dout
);

reg [2:0] cnt;
reg [3:0] data;
reg valid;

always @(posedge clk) begin
    if (!rst_n) begin
        cnt <= 3'd0;
    end else begin
        if (cnt == 3'd3) begin
            cnt <= 3'd0;
        end else begin
            cnt <= cnt + 1;
        end
    end
end

always @(posedge clk) begin
    if (!rst_n) begin
        valid <= 1'b0;
    end else begin
        if (cnt == 3'd3) begin
            valid <= 1'b1;
        end else begin
            valid <= 1'b0;
        end
    end
end

always @(posedge clk) begin
    if (!rst_n) begin
        data <= 4'd0;
    end else begin
        if (cnt == 3'd3) begin
            data <= d;
        end else begin
            data <= {data[2:0], data[3]};
        end
    end
end

assign dout = data[3];
assign valid_out = valid;

endmodule

module div_16bit(
    input [15:0] A,
    input [7:0] B,
    output [15:0] result,
    output [15:0] odd
);

    reg [15:0] dividend;
    reg [7:0] divisor;
    reg [15:0] quotient;
    reg [15:0] remainder;

    always @(*) begin
        dividend = A[15:8];
        divisor = B;
        quotient = 16'b0;
        remainder = 16'b0;

        if (dividend >= divisor) begin
            quotient = 16'b1;
            remainder = dividend - divisor;
        end
        else begin
            quotient = 16'b0;
            remainder = dividend;
        end
    end

    assign result = quotient;
    assign odd = remainder;

endmodule

module multi_8bit(
    input [7:0] A,
    input [7:0] B,
    output reg [15:0] product
);
    integer i;
    reg [7:0] A_shifted;
    reg [15:0] product_temp;
    always @(*) begin
        product_temp = 0;
        A_shifted = A;
        for (i = 0; i < 8; i = i + 1) begin
            if (B[i]) begin
                product_temp = product_temp + (A_shifted << i);
            end
        end
    end
    always @(*) begin
        product = product_temp;
    end
endmodule

module fsm(
    input IN,
    input CLK,
    input RST,
    output reg MATCH
);

reg [2:0] state, next_state;
parameter S0 = 3'b000, S1 = 3'b001, S2 = 3'b010, S3 = 3'b011, S4 = 3'b100;

always @(posedge CLK or posedge RST) begin
    if (RST) begin
        state <= S0;
        MATCH <= 1'b0;
    end
    else begin
        state <= next_state;
        MATCH <= (next_state == S4) ? 1'b1 : 1'b0;
    end
end

always @(*) begin
    case (state)
        S0: begin
            if (IN) next_state = S1;
            else next_state = S0;
        end
        S1: begin
            if (IN) next_state = S1;
            else next_state = S2;
        end
        S2: begin
            if (IN) next_state = S1;
            else next_state = S3;
        end
        S3: begin
            if (IN) next_state = S4;
            else next_state = S0;
        end
        S4: begin
            if (IN) next_state = S1;
            else next_state = S0;
        end
        default: next_state = S0;
    endcase
end

endmodule

module freq_div(
    input CLK_in,
    input RST,
    output reg CLK_50,
    output reg CLK_10,
    output reg CLK_1
);
  // Frequency division parameters
  parameter DIV_50 = 2;
  parameter DIV_10 = 10;
  parameter DIV_1 = 100;
  // Counter variables
  reg [1:0] cnt_50 = 0;
  reg [3:0] cnt_10 = 0;
  reg [6:0] cnt_1 = 0;
  // CLK_50 generation
  always @(posedge CLK_in or posedge RST) begin
    if (RST) begin
      CLK_50 <= 0;
    end else begin
      CLK_50 <= ~CLK_50;
    end
  end
  // CLK_10 generation
  always @(posedge CLK_in or posedge RST) begin
    if (RST) begin
      CLK_10 <= 0;
      cnt_10 <= 0;
    end else begin
      if (cnt_10 == DIV_10 - 1) begin
        CLK_10 <= ~CLK_10;
        cnt_10 <= 0;
      end else begin
        cnt_10 <= cnt_10 + 1;
      end
    end
  end
  // CLK_1 generation
  always @(posedge CLK_in or posedge RST) begin
    if (RST) begin
      CLK_1 <= 0;
      cnt_1 <= 0;
    end else begin
      if (cnt_1 == DIV_1 - 1) begin
        CLK_1 <= ~CLK_1;
        cnt_1 <= 0;
      end else begin
        cnt_1 <= cnt_1 + 1;
      end
    end
  end
endmodule

module alu(
    input [31:0] a,
    input [31:0] b,
    input [5:0] aluc,
    output [31:0] r,
    output zero,
    output carry,
    output negative,
    output overflow,
    output flag
);

    // Internal signals
    wire [31:0] result;
    wire [31:0] add_result;
    wire [31:0] sub_result;
    wire [31:0] and_result;
    wire [31:0] or_result;
    wire [31:0] xor_result;
    wire [31:0] sl_result;
    wire [31:0] sr_result;
    wire [31:0] sra_result;
    wire [31:0] lui_result;

    // ALU operations
    assign add_result = a + b;
    assign sub_result = a - b;
    assign and_result = a & b;
    assign or_result = a | b;
    assign xor_result = a ^ b;
    assign sl_result = a << b[4:0];
    assign sr_result = a >> b[4:0];
    assign sra_result = $signed(a) >>> b[4:0];
    assign lui_result = {b[15:0], 16'b0};

    // Output multiplexer
    assign result = (aluc == 6'b000000) ? add_result :
                    (aluc == 6'b000001) ? sub_result :
                    (aluc == 6'b000010) ? and_result :
                    (aluc == 6'b000011) ? or_result :
                    (aluc == 6'b000100) ? xor_result :
                    (aluc == 6'b000101) ? sl_result :
                    (aluc == 6'b000110) ? sr_result :
                    (aluc == 6'b000111) ? sra_result :
                    (aluc == 6'b001000) ? lui_result :
                    32'b0;

    // Flags
    assign zero = (result == 32'b0);
    assign carry = (aluc == 6'b000001) && (result < a);
    assign negative = (result[31] == 1'b1);
    assign overflow = (aluc == 6'b000001) && ((a[31] == b[31]) && (a[31] != result[31]));
    assign flag = (aluc == 6'b000001) ? overflow :
                  (aluc == 6'b000011) ? overflow :
                  (aluc == 6'b000100) ? overflow :
                  (aluc == 6'b000101) ? overflow :
                  1'b0;

    // Output
    assign r = result;

endmodule

module edge_detect(
    input clk,
    input rst_n,
    input a,
    output rise,
    output down
);

reg a_reg;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        a_reg <= 1'b0;
    end else begin
        a_reg <= a;
    end
end

assign rise = (a_reg == 1'b0 && a == 1'b1) ? 1'b1 : 1'b0;
assign down = (a_reg == 1'b1 && a == 1'b0) ? 1'b1 : 1'b0;

endmodule

